#pragma once\n#include <cstdint>\n#include <cstddef>\n\n// Naive version (for baseline comparison)\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\n    for (size_t i = 0; i < M; i++) {\n        for (size_t j = 0; j < K; j++) {\n            float sum = 0.0f;\n            for (size_t p = 0; p < K; p++) {\n                float a_val = A[i * K + p];\n                uint32_t packed = B[p * (K/32) + (j/32)];\n                float sign = ((packed >> (j%32)) & 1) ? 1.0f : -1.0f;\n                sum += a_val * sign;\n            }\n            C[i * K + j] = sum;\n        }\n    }\n}